def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 11):
            if ratio < 0.1 * j:
                increment = (j ** 2) * (1 - ratio) / (j + ratio + 1)
            else:
                increment = (j * ratio) / (j + 1)
            if j % 3 == 0:
                increment *= np.log1p(cap + j)
            elif j % 2 == 0:
                increment /= np.sqrt(cap + j)
            score += increment
        if cap < item * 1.5:
            score *= 2 - ratio
        elif cap > item * 4:
            score *= 0.7 + 0.3 * np.sin(cap)
        else:
            for k in range(1, 4):
                if (cap + k) % 2 == 0:
                    score += k / (cap + k)
                else:
                    score -= k * ratio / (cap + k)
        priorities[i] = score / (cap + 1) * np.exp(-ratio)
    return priorities
